NS="karma-rabbitmq-security-upgrade-lifec-87f54d93-cluster-a"
# Patch the StatefulSet to add the TLS secret volume and mount it
kubectl -n "$NS" patch statefulset rabbitmq --type=json -p='[
  {
    "op": "add",
    "path": "/spec/template/spec/volumes/-",
    "value": {
      "name": "tls",
      "secret": {
        "secretName": "rabbitmq-tls",
        "defaultMode": 256
      }
    }
  },
  {
    "op": "add",
    "path": "/spec/template/spec/containers/0/volumeMounts/-",
    "value": {
      "name": "tls",
      "mountPath": "/etc/rabbitmq/tls",
      "readOnly": true
    }
  }
]'
echo "StatefulSet patched"

NS="karma-rabbitmq-security-upgrade-lifec-87f54d93-cluster-a"
# Add port 5671 (AMQPS) to the rabbitmq ClusterIP service
kubectl -n "$NS" patch svc rabbitmq --type=json -p='[
  {
    "op": "add",
    "path": "/spec/ports/-",
    "value": {
      "name": "amqps",
      "port": 5671,
      "targetPort": 5671,
      "protocol": "TCP"
    }
  }
]'
# Add port 5671 to the headless service too
kubectl -n "$NS" patch svc rabbitmq-headless --type=json -p='[
  {
    "op": "add",
    "path": "/spec/ports/-",
    "value": {
      "name": "amqps",
      "port": 5671,
      "targetPort": 5671,
      "protocol": "TCP"
    }
  }
]'
echo "Services patched"
kubectl -n "$NS" get svc

